(function($){"use strict";function initColorPicker(widget){widget.find(".ip-widget-color-picker:not(.init)").addClass("init").wpColorPicker({change:function(event,ui){$(this).closest("form").find("input[type=hidden]").first().trigger("change");var element=event.target;var color=ui.color.toString()}});widget.find(".ip-widget-attributes-list .wp-color-result").each(function(){$(this).attr("data-name",$(this).closest("li").data("name"))})}function onFormUpdate(event,widget){console.log(event);alert(event.type);initColorPicker(widget)}var $document=$(document);$document.on("widget-added widget-updated",onFormUpdate);$document.ready(function(){$(".widget:has(.ip-widget-color-picker)").each(function(){initColorPicker($(this))})})})(jQuery);